import jsPDF from "jspdf";
import type { ScoredField } from "./app/assessment/types";

export interface PDFReportData {
  studentName: string;
  major: string;
  topThree: ScoredField[];
  summary?: string;
  shortTermGoal?: string;
  midTermGoal?: string;
  longTermGoal?: string;
  actionPlan?: string;
}

const TEMPLATE_P1 = "";
const TEMPLATE_P2 = "";
const PN_REGULAR  = "";
const PN_BOLD     = "";
const PN_SEMI     = "";
const KD_BOLD     = "";

const C = {
  black:   [15,  15,  15]  as [number,number,number],
  gold:    [255, 192, 15]  as [number,number,number],
  dkgray:  [59,  59,  57]  as [number,number,number],
  midgray: [120, 120, 118] as [number,number,number],
  border:  [180, 180, 178] as [number,number,number],
  green:   [26,  107, 60]  as [number,number,number],
  ltgreen: [237, 247, 242] as [number,number,number],
  bglight: [248, 248, 246] as [number,number,number],
};

export function generatePDF(data: PDFReportData): void {
  const { studentName, major, topThree, summary, shortTermGoal, midTermGoal, longTermGoal, actionPlan } = data;
  const doc = new jsPDF({ unit: "pt", format: "letter" });
  const W = 612, H = 792, M = 54;
  let y = 0;

  // ── Register Towson fonts
  doc.addFileToVFS("ProximaNova-Regular.ttf", PN_REGULAR);
  doc.addFileToVFS("ProximaNova-Bold.ttf", PN_BOLD);
  doc.addFileToVFS("ProximaNova-Semibold.ttf", PN_SEMI);
  doc.addFileToVFS("Kandal-Bold.ttf", KD_BOLD);
  doc.addFont("ProximaNova-Regular.ttf", "ProximaNova", "normal");
  doc.addFont("ProximaNova-Bold.ttf", "ProximaNova", "bold");
  doc.addFont("ProximaNova-Semibold.ttf", "ProximaNovaSemi", "normal");
  doc.addFont("Kandal-Bold.ttf", "Kandal", "bold");

  const PN = "ProximaNova";
  const KD = "Kandal";

  function drawTemplate(pageNum: number): void {
    doc.addImage(pageNum === 1 ? TEMPLATE_P2 : TEMPLATE_P1, "PNG", 0, 0, W, H);

    if (pageNum === 1) {
  // Department name - next to logo, vertically centered
  doc.setFont(PN, "bold");
  doc.setFontSize(14);
  doc.setTextColor(59, 59, 57);
  doc.text("Department of Computer", 235, 48, {align: "center"});
  doc.text("& Information Sciences", 235, 64, {align: "center"});

  // Form title - right aligned, bold
  doc.setFont(PN, "bold");
  doc.setFontSize(14);
  doc.setTextColor(59, 59, 57);
  doc.text("Student Information Report", W - M, 56, { align: "right" });
}
  }

  function sectionHeader(title: string): void {
    doc.setFillColor(...C.bglight);
    doc.rect(M, y, W - 2 * M, 20, "F");
    doc.setFillColor(...C.green);
    doc.rect(M, y, 4, 20, "F");
    doc.setDrawColor(...C.border);
    doc.setLineWidth(0.4);
    doc.rect(M, y, W - 2 * M, 20, "S");
    doc.setFont(PN, "bold");
    doc.setFontSize(9);
    doc.setTextColor(...C.dkgray);
    doc.text(title.toUpperCase(), M + 14, y + 13.5);
    y += 28;
  }

  function fieldPair(label1: string, value1: string, label2?: string, value2?: string): void {
    const cw = (W - 2 * M) / 2;
    doc.setFont(PN, "normal");
    doc.setFontSize(8);
    doc.setTextColor(...C.midgray);
    doc.text(label1, M, y);
    if (label2) doc.text(label2, M + cw, y);
    y += 11;
    doc.setFont(PN, "bold");
    doc.setFontSize(11);
    doc.setTextColor(...C.dkgray);
    doc.text(value1 || "—", M, y);
    if (label2) doc.text(value2 || "—", M + cw, y);
    y += 20;
  }

  function percentBar(label: string, pct: number, rank: number): void {
    doc.setFillColor(...C.gold);
    doc.circle(M + 8, y + 1, 7, "F");
    doc.setFont(PN, "bold");
    doc.setFontSize(8);
    doc.setTextColor(...C.black);
    doc.text(String(rank), M + 8, y + 4, { align: "center" });
    doc.setFont(PN, "bold");
    doc.setFontSize(10);
    doc.setTextColor(...C.dkgray);
    doc.text(label, M + 22, y + 4);
    doc.setFont(PN, "normal");
    doc.setFontSize(9);
    doc.setTextColor(...C.midgray);
    doc.text(`${pct}%`, W - M, y + 4, { align: "right" });
    y += 14;
    const barW = W - 2 * M;
    doc.setFillColor(...C.border);
    doc.roundedRect(M, y, barW, 7, 3, 3, "F");
    doc.setFillColor(...C.green);
    doc.roundedRect(M, y, Math.max(barW * (pct / 100), 6), 7, 3, 3, "F");
    y += 16;
  }

  function skillPills(skills: string[]): void {
    let sx = M, ty = y;
    skills.forEach((sk) => {
      const tw = doc.getTextWidth(sk) + 14;
      if (sx + tw > W - M) { sx = M; ty += 18; }
      doc.setFillColor(...C.ltgreen);
      doc.setDrawColor(...C.green);
      doc.setLineWidth(0.35);
      doc.roundedRect(sx, ty - 9, tw, 14, 7, 7, "FD");
      doc.setFont(PN, "bold");
      doc.setFontSize(8);
      doc.setTextColor(...C.green);
      doc.text(sk, sx + 7, ty);
      sx += tw + 5;
    });
    y = ty + 20;
  }

  function roleChips(roles: string[]): void {
    const cols = 2, cw = (W - 2 * M) / cols;
    roles.forEach((role, i) => {
      const rx = M + (i % cols) * cw;
      const ry = y + Math.floor(i / cols) * 18;
      doc.setFillColor(...C.bglight);
      doc.setDrawColor(...C.border);
      doc.setLineWidth(0.35);
      doc.roundedRect(rx, ry - 9, cw - 6, 14, 2, 2, "FD");
      doc.setFont(PN, "normal");
      doc.setFontSize(9);
      doc.setTextColor(...C.dkgray);
      doc.text(role, rx + 7, ry);
    });
    y += Math.ceil(roles.length / cols) * 18 + 10;
  }

  // ── PAGE 1
  drawTemplate(1);
  y = 104;

  sectionHeader("Student Information");
  fieldPair("Name", studentName, "Major", major);
  fieldPair("Report Date", new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" }));
  y += 4;

  sectionHeader("Career Results");
  doc.setFont(PN, "normal");
  doc.setFontSize(8.5);
  doc.setTextColor(...C.midgray);
  doc.text("Top career matches based on your assessment responses:", M, y);
  y += 14;
  topThree.forEach((r, i) => { percentBar(r.label, r.percentage, i + 1); y += 2; });
  y += 6;

  const top = topThree[0];
  sectionHeader(`Top Match: ${top.label}`);
  const descLines = doc.splitTextToSize(top.description, W - 2 * M - 20);
  const dboxH = descLines.length * 12 + 14;
  doc.setFillColor(...C.ltgreen);
  doc.setDrawColor(...C.green);
  doc.setLineWidth(0.4);
  doc.roundedRect(M, y, W - 2 * M, dboxH, 3, 3, "FD");
  doc.setFont(PN, "normal");
  doc.setFontSize(9);
  doc.setTextColor(...C.green);
  doc.text(descLines, M + 10, y + 10);
  y += dboxH + 12;

  sectionHeader("Key Skills");
  skillPills(top.skills);
  sectionHeader("Recommended Roles");
  roleChips(top.exampleRoles);
  sectionHeader("Relevant Certifications");
  roleChips(top.certifications);

  if (summary?.trim()) {
    sectionHeader("Student Summary");
    const sl = doc.splitTextToSize(summary.trim(), W - 2 * M - 20);
    const sbH = sl.length * 13 + 16;
    doc.setFillColor(252, 252, 250);
    doc.setDrawColor(...C.border);
    doc.roundedRect(M, y - 6, W - 2 * M, sbH, 3, 3, "FD");
    doc.setFont(PN, "normal");
    doc.setFontSize(9.5);
    doc.setTextColor(...C.dkgray);
    doc.text(sl, M + 10, y + 6);
    y += sbH + 12;
  }


  // Goals section
  const goals = [];
  if (shortTermGoal && shortTermGoal.trim()) goals.push({ label: "Short-term Goal (0-1 year)", value: shortTermGoal.trim() });
  if (midTermGoal && midTermGoal.trim())     goals.push({ label: "Mid-term Goal (1-5 years)",  value: midTermGoal.trim() });
  if (longTermGoal && longTermGoal.trim())   goals.push({ label: "Long-term Goal (5+ years)",  value: longTermGoal.trim() });
  if (goals.length > 0) {
    if (y > H - 120) { doc.addPage(); drawTemplate(2); y = 104; }
    sectionHeader("Career Goals");
    goals.forEach(({ label, value }) => {
      if (y > H - 80) { doc.addPage(); drawTemplate(2); y = 104; }
      doc.setFont(PN, "bold"); doc.setFontSize(8); doc.setTextColor(...C.midgray);
      doc.text(label.toUpperCase(), M, y); y += 10;
      const gl = doc.splitTextToSize(value, W - 2 * M - 20);
      const gbH = gl.length * 12 + 14;
      doc.setFillColor(252, 252, 250); doc.setDrawColor(...C.border);
      doc.roundedRect(M, y - 4, W - 2 * M, gbH, 3, 3, "FD");
      doc.setFont(PN, "normal"); doc.setFontSize(9); doc.setTextColor(...C.dkgray);
      doc.text(gl, M + 10, y + 6);
      y += gbH + 10;
    });
  }
  if (actionPlan && actionPlan.trim()) {
    if (y > H - 80) { doc.addPage(); drawTemplate(2); y = 104; }
    sectionHeader("My Action Plan");
    const al = doc.splitTextToSize(actionPlan.trim(), W - 2 * M - 20);
    const abH = al.length * 12 + 14;
    doc.setFillColor(252, 252, 250); doc.setDrawColor(...C.border);
    doc.roundedRect(M, y - 4, W - 2 * M, abH, 3, 3, "FD");
    doc.setFont(PN, "normal"); doc.setFontSize(9); doc.setTextColor(...C.dkgray);
    doc.text(al, M + 10, y + 6);
    y += abH + 12;
  }
  // ── PAGE 2
  doc.addPage();
  drawTemplate(2);
  y = 104;

  sectionHeader("All Career Match Details");
  topThree.forEach((result, i) => {
    if (y > H - 160) { doc.addPage(); drawTemplate(2); y = 104; }
    doc.setFillColor(...C.bglight);
    doc.rect(M, y, W - 2 * M, 16, "F");
    doc.setFillColor(...(i === 0 ? C.gold : C.green));
    doc.circle(M + 8, y + 8, 6, "F");
    doc.setFont(PN, "bold"); doc.setFontSize(8);
    doc.setTextColor(...(i === 0 ? C.black : [255,255,255] as [number,number,number]));
    doc.text(String(i + 1), M + 8, y + 11, { align: "center" });
    doc.setFont(PN, "bold"); doc.setFontSize(10); doc.setTextColor(...C.dkgray);
    doc.text(result.label, M + 20, y + 11);
    doc.setFont(PN, "normal"); doc.setFontSize(9); doc.setTextColor(...C.midgray);
    doc.text(`${result.percentage}% match`, W - M, y + 11, { align: "right" });
    y += 22;

    const colW = (W - 2 * M) / 2 - 6;
    const startY = y;
    doc.setFont(PN, "bold"); doc.setFontSize(8); doc.setTextColor(...C.midgray);
    doc.text("SKILLS", M, y); y += 10;
    result.skills.forEach((sk: string) => {
      const tw = Math.min(doc.getTextWidth(sk) + 12, colW);
      doc.setFillColor(...C.ltgreen); doc.setDrawColor(...C.green); doc.setLineWidth(0.3);
      doc.roundedRect(M, y - 8, tw, 12, 6, 6, "FD");
      doc.setFont(PN, "normal"); doc.setFontSize(7.5); doc.setTextColor(...C.green);
      doc.text(sk, M + 6, y); y += 14;
    });
    const leftEndY = y;
    y = startY;
    const rx = M + colW + 12;
    doc.setFont(PN, "bold"); doc.setFontSize(8); doc.setTextColor(...C.midgray);
    doc.text("ROLES", rx, y); y += 10;
    result.exampleRoles.forEach((role: string) => {
      doc.setFillColor(...C.bglight); doc.setDrawColor(...C.border); doc.setLineWidth(0.3);
      doc.roundedRect(rx, y - 8, colW, 12, 2, 2, "FD");
      doc.setFont(PN, "normal"); doc.setFontSize(7.5); doc.setTextColor(...C.dkgray);
      doc.text(role, rx + 6, y); y += 14;
    });
    y = Math.max(leftEndY, y) + 10;
    if (i < topThree.length - 1) {
      doc.setDrawColor(...C.border); doc.setLineWidth(0.3);
      doc.line(M, y, W - M, y); y += 10;
    }
  });

  if (y > H - 200) { doc.addPage(); drawTemplate(2); y = 104; }
  sectionHeader("Suggested Next Steps");
  const steps = [
    `Meet with your academic advisor to align course selections toward ${top.label}.`,
    `Pursue certifications: ${top.certifications.join(", ")}.`,
    "Build a project portfolio on GitHub showcasing your key skills.",
    "Apply for internships aligned with your top career match.",
    "Attend career fairs and CIS department networking events.",
    "Connect with alumni and industry professionals through LinkedIn and networking events.",
  ];
  steps.forEach((step, i) => {
    if (y > H - 80) { doc.addPage(); drawTemplate(2); y = 104; }
    doc.setFillColor(...C.gold);
    doc.circle(M + 7, y + 1, 5, "F");
    doc.setFont(PN, "bold"); doc.setFontSize(8); doc.setTextColor(15,15,15);
    doc.text(String(i + 1), M + 7, y + 4, { align: "center" });
    const sl = doc.splitTextToSize(step, W - 2 * M - 22);
    doc.setFont(PN, "normal"); doc.setFontSize(9); doc.setTextColor(...C.dkgray);
    doc.text(sl, M + 20, y + 4);
    y += sl.length * 12 + 8;
  });

  doc.save(`TU_Career_Report_${studentName.replace(/\s+/g,"_").toLowerCase()}.pdf`);
}